const items = $input.all();

// No insights yet (fresh install)
if (items.length === 0 || !items[0].json.last_review_date) {
  // Check if there are any trades at all
  return [{
    json: {
      insights: null,
      summary: 'No reviews yet. This is a fresh start.',
      needs_review: false,
      trades_since_review: 0,
      response: 'No performance insights available yet. Start scanning and logging trades to build your history.'
    }
  }];
}

const data = items[0].json;
const reviewOverdue = data.review_overdue === true;
const tradesSince = parseInt(data.trades_since_review) || 0;
const enoughTrades = tradesSince >= 5;

let response = '';
if (data.insights) {
  response += `LATEST INSIGHTS (win rate: ${data.win_rate}%, ${data.trades_analyzed} trades analyzed):\n`;
  let insightsArr = data.insights;
  try { insightsArr = typeof insightsArr === 'string' ? JSON.parse(insightsArr) : insightsArr; } catch(e) { insightsArr = []; }
  if (Array.isArray(insightsArr)) {
    insightsArr.forEach((insight, i) => { response += `${i + 1}. ${insight}\n`; });
  }
  response += `\nSummary: ${data.summary || 'N/A'}`;
}

response += `\n\nReview status: ${reviewOverdue && enoughTrades ? 'REVIEW DUE - suggest running a review' : 'Up to date'}`;
response += `\nTrades since last review: ${tradesSince}`;

return [{
  json: {
    insights: data.insights,
    adjustments: data.adjustments,
    summary: data.summary,
    win_rate: data.win_rate,
    last_review_date: data.last_review_date,
    needs_review: reviewOverdue && enoughTrades,
    trades_since_review: tradesSince,
    response
  }
}];
